import { Challenge, ChallengeDocument } from './challenge.schema';
import { InjectModel } from '@nestjs/mongoose';
import { Injectable } from '@nestjs/common';
import { Model } from 'mongoose';

@Injectable()
export class ChallengeService {
  constructor(
    @InjectModel(Challenge.name)
    private readonly challengeModel: Model<Challenge>,
  ) {}

  async isStarted(challenger: string): Promise<boolean> {
    const challenge = await this.challengeModel
      .findOne({
        challenger,
        started: true,
      })
      .exec();
    return challenge && challenge.started;
  }

  async start(challenger: string, endedAt: number): Promise<boolean> {
    const started = await this.isStarted(challenger);

    if (started) {
      return false;
    }

    await this.challengeModel.create({
      endedAt,
      challenger,
      started: true,
    });
    return true;
  }

  async findByChallenger(
    challenger: string,
    started = false,
  ): Promise<ChallengeDocument[]> {
    return this.challengeModel
      .find({
        challenger,
        started,
      })
      .exec();
  }

  async stop(challenger: string): Promise<ChallengeDocument> {
    const started = await this.isStarted(challenger);
    if (started) {
      const challenge = await this.findByChallenger(challenger, true);
      if (challenge) {
        const startedAt = new Date() as unknown as number;
        const endedAt = challenge[0].endedAt as unknown as number;
        const remaining = (endedAt - startedAt) / (1000 * 60 * 60 * 24);
        if (remaining < 0) {
          return this.update(false, false, true, challenge[0]._id.toString());
        } else {
          return this.update(
            false,
            true,
            false,
            challenge[0]._id.toString(),
            Date.now(),
          );
        }
      }
    }
    return null;
  }

  async update(
    started: boolean,
    lost: boolean,
    won: boolean,
    id: string,
    relapseAt?: number,
  ): Promise<ChallengeDocument> {
    const challenge = await this.challengeModel.findById(id).exec();
    if (challenge) {
      await this.challengeModel
        .findByIdAndUpdate(
          {
            _id: id,
          },
          { started, lost, won, relapseAt },
          {
            new: true,
          },
        )
        .exec();
    }
    return challenge;
  }
}

import { Message } from '@google-cloud/pubsub';
import { PubsubBatchManagerConfigurationInvalidError } from './pubsub-configuration.errors';
import { promiseWithResolvers } from './utils';

type BatchItem = {
  message: Message;
  deferred: ReturnType<typeof promiseWithResolvers<void>>;
};

export interface BatchManagerOptions {
  maxMessages: number;
  maxWaitTimeMilliseconds: number;
}

export class PubsubSubscriptionBatchManager {
  private buffer: BatchItem[] = [];
  private timer: NodeJS.Timeout | null = null;

  private listener: ((batch: BatchItem[]) => Promise<void>) | null = null;

  constructor(private readonly options?: BatchManagerOptions) {
    const maxMessages = options?.maxMessages;

    if (!Number.isInteger(maxMessages) || maxMessages! <= 0) {
      throw new PubsubBatchManagerConfigurationInvalidError({
        key: 'subscription.batchManagerOptions.maxMessages',
        value: maxMessages,
        reason: 'Must be a positive integer greater than 0.',
      });
    }

    const maxWaitTimeMilliseconds = options?.maxWaitTimeMilliseconds;

    if (
      !Number.isInteger(maxWaitTimeMilliseconds) ||
      maxWaitTimeMilliseconds! <= 0
    ) {
      throw new PubsubBatchManagerConfigurationInvalidError({
        key: 'subscription.batchManagerOptions.maxWaitTimeMilliseconds',
        value: maxWaitTimeMilliseconds,
        reason: 'Must be a positive integer greater than 0.',
      });
    }
  }

  public on(handler: (batch: BatchItem[]) => Promise<void>) {
    this.listener = handler;
  }

  public add(message: Message) {
    const deferred = promiseWithResolvers<void>();

    this.buffer.push({ deferred, message });

    if (this.buffer.length >= this.options!.maxMessages) {
      this.flush();
    } else if (!this.timer) {
      this.timer = setTimeout(() => {
        void this.flush();
      }, this.options!.maxWaitTimeMilliseconds);
    }

    return deferred.promise;
  }

  public async flush() {
    if (this.timer) {
      clearTimeout(this.timer);
      this.timer = null;
    }

    if (this.buffer.length === 0) {
      return;
    }

    const batch = this.buffer;
    this.buffer = [];

    if (this.listener) {
      await this.listener(batch);
    }
  }
}

import { Injectable } from '@nestjs/common';
import { Buffer } from 'node:buffer';
import Stripe from 'stripe';
import {
  InjectStripeClient,
  InjectStripeModuleConfig,
} from './stripe.decorators';
import {
  StripeModuleConfig,
  StripeSecrets,
  StripeWebhookMode,
} from './stripe.interfaces';

@Injectable()
export class StripePayloadService {
  private readonly stripeSecrets: StripeSecrets;
  private readonly stripeThinSecrets: StripeSecrets;

  constructor(
    @InjectStripeModuleConfig()
    readonly config: StripeModuleConfig,
    @InjectStripeClient()
    private readonly stripeClient: Stripe,
  ) {
    this.stripeSecrets = config.webhookConfig?.stripeSecrets || {};
    this.stripeThinSecrets = config.webhookConfig?.stripeThinSecrets || {};
  }

  async tryHydratePayload(
    signature: string,
    payload: Buffer,
    mode: StripeWebhookMode,
  ): Promise<{ type: string }> {
    const decodedPayload = JSON.parse(
      Buffer.isBuffer(payload) ? payload.toString('utf8') : payload,
    );

    const secrets = this.getWebhookSecrets(mode);
    const secretToUse = this.getWebhookSecret(decodedPayload, secrets);

    switch (mode) {
      case StripeWebhookMode.SNAPSHOT:
        return this.stripeClient.webhooks.constructEventAsync(
          payload,
          signature,
          secretToUse,
        );

      case StripeWebhookMode.THIN:
        return this.stripeClient.webhooks.constructEventAsync(
          payload,
          signature,
          secretToUse,
        );
    }
  }

  private getWebhookSecrets(mode: StripeWebhookMode) {
    switch (mode) {
      case StripeWebhookMode.SNAPSHOT:
        return this.stripeSecrets;
      case StripeWebhookMode.THIN:
        return this.stripeThinSecrets;
    }
  }

  private getWebhookSecret(
    evt: Stripe.EventBase,
    secrets: StripeSecrets,
  ): string {
    let secret: string | undefined;

    if (!evt.account) {
      secret = evt.livemode ? secrets.account : secrets.accountTest;
    } else {
      secret = evt.livemode ? secrets.connect : secrets.connectTest;
    }

    if (!secret) {
      throw new Error(
        'Could not determine which secret to use for this webhook call!',
      );
    }

    return secret;
  }
}

import { join, Path, strings } from '@angular-devkit/core';
import {
  apply,
  branchAndMerge,
  chain,
  mergeWith,
  move,
  noop,
  Rule,
  SchematicContext,
  template,
  Tree,
  url,
} from '@angular-devkit/schematics';
import { formatFiles } from '../../utils/format-files.rule';
import { normalizeToKebabOrSnakeCase } from '../../utils/formatting';
import {
  DeclarationOptions,
  ModuleDeclarator,
} from '../../utils/module.declarator';
import { ModuleFinder } from '../../utils/module.finder';
import { Location, NameParser } from '../../utils/name.parser';
import { mergeSourceRoot } from '../../utils/source-root.helpers';
import { ModuleOptions } from './module.schema';

export function main(options: ModuleOptions): Rule {
  options = transform(options);
  return (tree: Tree, context: SchematicContext) => {
    return branchAndMerge(
      chain([
        mergeSourceRoot(options),
        addDeclarationToModule(options),
        mergeWith(generate(options)),
        options.format === true ? formatFiles() : noop(),
      ]),
    )(tree, context);
  };
}

function transform(source: ModuleOptions): ModuleOptions {
  const target: ModuleOptions = Object.assign({}, source);
  target.metadata = 'imports';
  target.type = 'module';

  const location: Location = new NameParser().parse(target);
  target.name = normalizeToKebabOrSnakeCase(location.name);
  target.path = normalizeToKebabOrSnakeCase(location.path);
  target.language = target.language !== undefined ? target.language : 'ts';

  target.path = target.flat
    ? target.path
    : join(target.path as Path, target.name);
  return target;
}

function generate(options: ModuleOptions) {
  return (context: SchematicContext) =>
    apply(url(join('./files' as Path, options.language)), [
      template({
        ...strings,
        ...options,
      }),
      move(options.path),
    ])(context);
}

function addDeclarationToModule(options: ModuleOptions): Rule {
  return (tree: Tree) => {
    if (options.skipImport !== undefined && options.skipImport) {
      return tree;
    }
    options.module = new ModuleFinder(tree).find({
      name: options.name,
      path: options.path as Path,
    });
    if (!options.module) {
      return tree;
    }
    const content = tree.read(options.module).toString();
    const declarator: ModuleDeclarator = new ModuleDeclarator();
    tree.overwrite(
      options.module,
      declarator.declare(content, options as DeclarationOptions),
    );
    return tree;
  };
}

