import { IPermission, IResource } from '../';
import {
  ClassType,
  DecoratorTypeOptions,
  ensureReflectMetadataExists,
} from '@ultimatebackend/common';

export class MetadataStorage {
  fields: FilterableMetadata[] = [];
  resources: ResourceMetadata[] = [];
  permissions: PermissionMetadata[] = [];
  instances: InstanceMetadata[] = [];

  constructor() {
    ensureReflectMetadataExists();
  }

  collectClassFieldMetadata(definition: FilterableMetadata) {
    this.fields.push(definition);
  }

  collectPermissionsMetadata(definition: PermissionMetadata) {
    this.permissions.push(definition);
  }

  collectResourcesMetadata(definition: ResourceMetadata) {
    this.resources.push(definition);
  }

  collectInstanceMetadata(definition: InstanceMetadata) {
    this.instances.push(definition);
  }

  clear() {
    this.fields = [];
    this.resources = [];
    this.permissions = [];
    this.instances = [];
  }
}

export interface FilterableMetadata {
  getType?: TypeValueThunk;
  typeOptions?: TypeOptions;
  getObjectType?: ClassTypeResolver;
  methodName: string;
  fieldType: string | ClassType<any>;
  name: string;
  // tslint:disable-next-line:ban-types
  target: Function;
  objectType: any;
  filterSchema?: any;
}

// tslint:disable-next-line:ban-types
export type TypeValue = ClassType | Function | object | symbol;
export type TypeValueThunk = (type?: void) => TypeValue;
export type ClassTypeResolver = (of?: void) => ClassType;

export interface TypeOptions extends DecoratorTypeOptions {
  array?: boolean;
  isEnum?: boolean;
  arrayDepth?: number;
}

export interface PermissionMetadata {
  getType?: TypeValueThunk;
  typeOptions?: TypeOptions;
  getObjectType?: ClassTypeResolver;
  methodName: string;
  fieldType: string | ClassType<any>;
  name: string;
  // tslint:disable-next-line:ban-types
  target: Function;
  objectType: any;
  filterSchema?: any;
  options?: IPermission;
}

export interface ResourceMetadata {
  prototype?: any;
  fieldType: string | ClassType<any>;
  name: string;
  // tslint:disable-next-line:ban-types
  target: Function;
  objectType: any;
  options?: IResource;
}

export interface InstanceMetadata {
  prototype?: any;
  getObjectType?: ClassTypeResolver;
  fieldType: string | ClassType<any>;
  name: string;
  // tslint:disable-next-line:ban-types
  target: Function;
  objectType: any;
}

import moment from 'moment';
import Joi from 'joi';
import jwt from 'jsonwebtoken';
import { TokenType } from '@/auth/enums/token-type.enum';
import { CommandHandler, ICommandHandler } from '@nestjs/cqrs';
import { AuthDto } from '@/auth/dtos/auth.dto';
import { Inject } from '@nestjs/common';
import { IAuthRepository } from '@/data/repositories/auth.repository';
import { Token } from '@/auth/entities/token.entity';
import configs from 'building-blocks/configs/configs';

export class GenerateToken {
  userId: number;

  constructor(request: Partial<GenerateToken> = {}) {
    Object.assign(this, request);
  }
}

const generateTokenValidations = {
  params: Joi.object().keys({
    userId: Joi.number().integer().required()
  })
};

const generateJwtToken = (
  userId: number,
  expires: number,
  type: TokenType,
  secret: string = configs.jwt.secret
): string => {
  const payload = {
    sub: userId,
    iat: moment().unix(),
    exp: expires,
    type
  };
  return jwt.sign(payload, secret);
};

@CommandHandler(GenerateToken)
export class GenerateTokenHandler implements ICommandHandler<GenerateToken> {
  constructor(@Inject('IAuthRepository') private readonly authRepository: IAuthRepository) {}

  async execute(command: GenerateToken): Promise<AuthDto> {
    await generateTokenValidations.params.validateAsync(command);

    const accessTokenExpires = moment().add(configs.jwt.accessExpirationMinutes, 'minutes');
    const accessToken = generateJwtToken(
      command.userId,
      accessTokenExpires.unix(),
      TokenType.ACCESS
    );

    const refreshTokenExpires = moment().add(configs.jwt.refreshExpirationDays, 'days');
    const refreshToken = generateJwtToken(
      command.userId,
      refreshTokenExpires.unix(),
      TokenType.REFRESH
    );

    await this.authRepository.createToken(
      new Token({
        token: accessToken,
        refreshToken: refreshToken,
        expires: accessTokenExpires.toDate(),
        type: TokenType.ACCESS,
        blacklisted: false,
        userId: command.userId
      })
    );

    const result = {
      access: {
        token: accessToken,
        expires: accessTokenExpires.toDate()
      },
      refresh: {
        token: refreshToken,
        expires: refreshTokenExpires.toDate()
      }
    };

    return new AuthDto(result);
  }
}

import { Injectable, Scope } from '@nestjs/common';
import { createLogger, Logger, transports } from 'winston';

import { RequestContext } from '../request-context/request-context.dto';

@Injectable({ scope: Scope.TRANSIENT })
export class AppLogger {
  private context?: string;
  private logger: Logger;

  public setContext(context: string): void {
    this.context = context;
  }

  constructor() {
    this.logger = createLogger({
      transports: [new transports.Console()],
    });
  }

  error(
    ctx: RequestContext,
    message: string,
    meta?: Record<string, any>,
  ): Logger {
    const timestamp = new Date().toISOString();

    return this.logger.error({
      message,
      contextName: this.context,
      ctx,
      timestamp,
      ...meta,
    });
  }

  warn(
    ctx: RequestContext,
    message: string,
    meta?: Record<string, any>,
  ): Logger {
    const timestamp = new Date().toISOString();

    return this.logger.warn({
      message,
      contextName: this.context,
      ctx,
      timestamp,
      ...meta,
    });
  }

  debug(
    ctx: RequestContext,
    message: string,
